import './App.css';
import { Link, Route, Routes } from 'react-router-dom';
import Home from './components/content/1';
import About from './components/Header/Header';
import Header from './components/Header/Header';
import One from './components/content/1';
import Two from './components/content/2';
import Three from './components/content/3';
import Fore from './components/content/4';
import Five from './components/content/5';
import Six from './components/content/6';
import Seven from './components/content/7';
import Eight from './components/content/8';
import Nine from './components/content/9';




function App() {
  return (
    <>
    <div className='header'>
    <Header/>
    </div>
    <div className='container'>
          <nav className='sidenav'>
            <ul>
              <li><Link to="/1">1</Link><br></br></li> {" "}
              <li><Link to="/2">2</Link><br></br></li>
              <li><Link to="/3">3</Link><br></br></li>
              <li><Link to="/4">4</Link><br></br></li>
              <li><Link to="/5">5</Link><br></br></li>
              <li><Link to="/6">6</Link><br></br></li>
              <li><Link to="/7">7</Link><br></br></li>
            </ul>
          </nav>


          <div  className='maincontent'>
          <Routes>
              <Route path="/1" element={<One />} />
              <Route path="/2" element={<Two/>} />
              <Route path="/3" element={<Three/>} />
              <Route path="/4" element={<Four/>} />
              <Route path="/5" element={<Five/>} />
              <Route path="/6" element={<Six/>} />
              <Route path="/7" element={<Seven/>} />
              <Route path="/8" element={<Eight/>} />
              <Route path="/9" element={<Nine/>} />
          </Routes>
          </div>
    </div>
    </>
  );
}

export default App;
